// ─────────────────────────────────────────────
// ROUTE TRANSFER (Fleet: move every route from one tail to another)
// ─────────────────────────────────────────────
// Returns { ok:true } or { ok:false, reason }. Shared by the TRANSFER_ROUTES
// reducer and the Fleet UI, so the tail picker can filter compatible aircraft
// and explain why an aircraft is greyed out. Frequencies don't change, so gate
// and slot budgets are unaffected; the network moves wholesale, so the usual
// connectivity rule is waived.
export function transferCompatibility(state, fromAircraftId, toAircraftId) {
  if (fromAircraftId === toAircraftId) return { ok: false, reason: 'Same aircraft' };
  const from     = state.fleet.find(a => a.id === fromAircraftId);
  const to       = state.fleet.find(a => a.id === toAircraftId);
  const fromType = from ? getAircraftType(from.typeId) : null;
  const toType   = to   ? getAircraftType(to.typeId)   : null;
  if (!from || !to || !fromType || !toType) return { ok: false, reason: 'Aircraft not found' };

  const paxRoutes   = state.routes.filter(r => r.aircraftId === fromAircraftId);
  const cargoRoutes = (state.cargoRoutes ?? []).filter(r => r.aircraftId === fromAircraftId);
  const all = [...paxRoutes, ...cargoRoutes];
  if (all.length === 0) return { ok: false, reason: 'No routes to transfer' };

  // Target must be an open tail — a swap, not a merge onto a working aircraft.
  const targetBusy = state.routes.some(r => r.aircraftId === toAircraftId)
    || (state.cargoRoutes ?? []).some(r => r.aircraftId === toAircraftId);
  if (targetBusy) return { ok: false, reason: 'Already flying routes' };

  // Pax routes need a passenger aircraft; cargo routes need a freighter.
  if (paxRoutes.length   > 0 && toType.freighter)  return { ok: false, reason: 'Freighter — passenger routes need a passenger aircraft' };
  if (cargoRoutes.length > 0 && !toType.freighter) return { ok: false, reason: 'Cargo routes need a freighter' };

  // Range: every leg of every route must be within the new tail's reach.
  const range = effectiveRangeKm(to, toType);
  for (const r of all) {
    if (routeMaxLegKm(r) > range) return { ok: false, reason: `Out of range: ${r.origin}–${r.destination}` };
  }

  // Regulatory restrictions re-checked per leg with the NEW aircraft category
  // (pair frequencies are unchanged, so totals stay as already approved).
  if (toType.category !== fromType.category) {
    const allOps = [...state.routes, ...(state.cargoRoutes ?? [])];
    for (const r of all) {
      for (const l of routeLegs(r)) {
        const pk = routePairKey(l.from, l.to);
        const pairFreq = allOps.reduce((s, o) =>
          routeLegs(o).some(ol => routePairKey(ol.from, ol.to) === pk) ? s + (o.weeklyFrequency ?? 0) : s, 0);
        if (checkRouteRestrictions(l.from, l.to, routeDistanceKm(l.from, l.to), pairFreq,
              toType.category, { routes: allOps, excludeKey: pk }))
          return { ok: false, reason: `Not permitted at ${l.from}–${l.to}` };
      }
    }
  }

  // Block hours on the new type — per-month peak, so counter-seasonal routes
  // that never overlap can share the budget (mirrors ADD_ROUTE).
  const peakBlockHrs = Math.max(...Array.from({ length: 12 }, (_, i) => i + 1).map(m => all
    .filter(r => isRouteActive(r, m))
    .reduce((s, r) => s + routeBlockHours(r, toType, r.weeklyFrequency), 0)));
  if (peakBlockHrs > MAX_WEEKLY_BLOCK_HOURS) return { ok: false, reason: 'Too slow — exceeds weekly block hours' };

  return { ok: true };
}

// ─────────────────────────────────────────────
// FREQUENCY CHANGE GUARD (Routes: change one route's weekly frequency)
// ─────────────────────────────────────────────
// Returns null if `newFreq` is allowed for the route, else a short player-facing
// reason. Shared by the UPDATE_FREQUENCY reducer and the Route detail UI, so the
// −/+ stepper enables/disables and explains exactly what the engine enforces.
// Reductions only free capacity → always allowed. Increases mirror ADD_ROUTE's
// per-month PEAK logic (counter-seasonal routes that never share a month can
// share the aircraft/gate budget) plus the regulatory perimeter/cap check.
export function frequencyChangeBlockReason(state, routeId, newFreq) {
  const route = state.routes.find(r => r.id === routeId);
  if (!route) return 'Route not found';
  const target = Math.max(1, Math.round(Number(newFreq) || 0));
  if (target <= route.weeklyFrequency) return null; // reductions always allowed

  const aircraft = state.fleet.find(a => a.id === route.aircraftId);
  const type     = aircraft ? getAircraftType(aircraft.typeId) : null;
  if (!type) return null; // no aircraft/type → nothing to enforce

  const dist   = routeDistanceKm(route.origin, route.destination);
  const months = routeActiveMonths(route);
  const freqOf = (r) => (r.id === route.id ? target : r.weeklyFrequency);

  // Regulatory (perimeter rules, per-pair frequency caps): peak proposed weekly
  // frequency on this city-pair across the route's active months.
  const pairKey = [route.origin, route.destination].sort().join('-');
  const pairRoutes = state.routes.filter(r => [r.origin, r.destination].sort().join('-') === pairKey);
  const peakPairFreq = Math.max(0, ...months.map(m =>
    pairRoutes.filter(r => isRouteActive(r, m)).reduce((s, r) => s + freqOf(r), 0)));
  if (checkRouteRestrictions(route.origin, route.destination, dist, peakPairFreq, type.category,
        { routes: state.routes, excludeKey: pairKey })) return 'Regulatory frequency cap on this route';

  // Block-hours on this aircraft, per-month peak, with this route at the new freq.
  const acRoutes = state.routes.filter(r => r.aircraftId === route.aircraftId);
  const peakBlockHrs = Math.max(0, ...months.map(m =>
    acRoutes.filter(r => isRouteActive(r, m)).reduce((s, r) =>
      s + weeklyBlockHours(routeDistanceKm(r.origin, r.destination), freqOf(r), type), 0)));
  if (peakBlockHrs > MAX_WEEKLY_BLOCK_HOURS) return "Aircraft's weekly block-hour limit";

  // Gate slots at each endpoint, per-month peak.
  const gates = state.gates ?? {};
  const peakSlotsAt = (code) => Math.max(0, ...months.map(m => state.routes
    .filter(r => (r.origin === code || r.destination === code) && isRouteActive(r, m))
    .reduce((s, r) => s + freqOf(r), 0)));
  if (peakSlotsAt(route.origin)      > (gates[route.origin]      ?? 0) * SLOTS_PER_GATE) return `No free gate slots at ${route.origin}`;
  if (peakSlotsAt(route.destination) > (gates[route.destination] ?? 0) * SLOTS_PER_GATE) return `No free gate slots at ${route.destination}`;

  return null;
}

